mapper.select:
SELECT d.device_id, d.device_name, g.group_name, latest.soc, CASE WHEN latest.soc IS NULL THEN 'NO_DATA' WHEN latest.soc = 0 THEN 'OFFLINE' WHEN latest.soc < 20 THEN 'ERROR' WHEN latest.soc < 40 THEN 'WARNING' ELSE 'NORMAL' END AS status FROM ess_device d
LEFT JOIN ess_device_group g ON d.group_id = g.group_id
LEFT JOIN ( SELECT device_id, soc FROM ( SELECT device_id, soc, ROW_NUMBER() OVER ( PARTITION BY device_id ORDER BY record_time DESC ) AS rn FROM monitoring WHERE record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND record_time < DATE_ADD( STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY ) AND MINUTE(record_time) = 0 ) ranked WHERE rn = 1 ) latest ON d.device_id = latest.device_id
WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
ORDER BY d.device_id ASC

SELECT user_type
FROM ess_member
WHERE member_id = #{memberId}

SELECT IFNULL(g.group_name, '미지정 그룹') AS label, IFNULL( SUM( CASE WHEN m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 THEN m.solar_generation_kwh END ), 0 ) AS generation FROM ess_device d LEFT JOIN ess_device_group g ON d.group_id = g.group_id LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY) AND MINUTE(m.record_time) = 0
WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
GROUP BY d.group_id, g.group_name ORDER BY generation DESC LIMIT #{limit}

SELECT d.device_name AS label, IFNULL( SUM( CASE WHEN m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 THEN m.solar_generation_kwh END ), 0 ) AS generation FROM ess_device d LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY) AND MINUTE(m.record_time) = 0
WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY d.device_id, d.device_name ORDER BY generation DESC LIMIT #{limit}

SELECT t.label,
IFNULL(SUM(t.selected_generation), 0) AS selectedGeneration, IFNULL(SUM(t.previous_generation), 0) AS previousGeneration, IFNULL(SUM(t.selected_generation), 0) - IFNULL(SUM(t.previous_generation), 0) AS generationDiff,
IFNULL(AVG(t.selected_soc), 0) AS selectedSoc, IFNULL(AVG(t.previous_soc), 0) AS previousSoc
FROM ( SELECT DATE_FORMAT(m.record_time, '%H:00') AS label, m.solar_generation_kwh AS selected_generation, 0 AS previous_generation, m.soc AS selected_soc, NULL AS previous_soc FROM monitoring m JOIN ess_device d ON m.device_id = d.device_id WHERE d.member_id = #{memberId} AND DATE(m.record_time) = #{selectedDate} AND MINUTE(m.record_time) = 0
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
UNION ALL
SELECT DATE_FORMAT(m.record_time, '%H:00') AS label, 0 AS selected_generation, m.solar_generation_kwh AS previous_generation, NULL AS selected_soc, m.soc AS previous_soc FROM monitoring m JOIN ess_device d ON m.device_id = d.device_id WHERE d.member_id = #{memberId} AND DATE(m.record_time) = DATE_SUB(#{selectedDate}, INTERVAL 1 DAY) AND MINUTE(m.record_time) = 0
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
) t
GROUP BY t.label ORDER BY t.label

SELECT t.label,
IFNULL(SUM(t.selected_generation), 0) AS selectedGeneration, IFNULL(SUM(t.previous_generation), 0) AS previousGeneration, IFNULL(SUM(t.selected_generation), 0) - IFNULL(SUM(t.previous_generation), 0) AS generationDiff,
0 AS selectedSoc, 0 AS previousSoc
FROM ( SELECT d.device_name AS label, m.solar_generation_kwh AS selected_generation, 0 AS previous_generation FROM monitoring m JOIN ess_device d ON m.device_id = d.device_id WHERE d.member_id = #{memberId} AND DATE(m.record_time) = #{selectedDate} AND MINUTE(m.record_time) = 0
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
UNION ALL
SELECT d.device_name AS label, 0 AS selected_generation, m.solar_generation_kwh AS previous_generation FROM monitoring m JOIN ess_device d ON m.device_id = d.device_id WHERE d.member_id = #{memberId} AND DATE(m.record_time) = DATE_SUB(#{selectedDate}, INTERVAL 1 DAY) AND MINUTE(m.record_time) = 0
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
) t
GROUP BY t.label ORDER BY selectedGeneration DESC

SELECT DATE_FORMAT(el.log_date, '%m-%d') AS label, IFNULL(SUM(el.daily_kwh), 0) AS dailyKwh, IFNULL(SUM(el.cost), 0) AS savedCost, IFNULL(AVG(el.efficiency), 0) AS efficiency, IFNULL(SUM(el.daily_kwh), 0) AS value
FROM energy_log el JOIN ess_device d ON el.device_id = d.device_id
WHERE d.member_id = #{memberId} AND el.log_date BETWEEN DATE_SUB(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 6 DAY) AND STR_TO_DATE(#{selectedDate}, '%Y-%m-%d')
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY el.log_date ORDER BY el.log_date ASC

SELECT DATE_FORMAT(el.log_date, '%Y-%m') AS label, IFNULL(SUM(el.daily_kwh), 0) AS monthlyKwh, IFNULL(SUM(el.cost), 0) AS savedCost, IFNULL(AVG(el.efficiency), 0) AS efficiency, IFNULL(SUM(el.daily_kwh), 0) AS value
FROM energy_log el JOIN ess_device d ON el.device_id = d.device_id
WHERE d.member_id = #{memberId} AND el.log_date >= DATE_FORMAT( DATE_SUB(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 5 MONTH), '%Y-%m-01' ) AND el.log_date <= LAST_DAY(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'))
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY DATE_FORMAT(el.log_date, '%Y-%m') ORDER BY label ASC
